cat << 'EOF' > src/App.jsx
import React, { useState, useEffect } from 'react';

function App() {
  const [status, setStatus] = useState('IDLE');
  const [logs, setLogs] = useState(['[SYSTEM] Kiosk initialized. Ready for wake word...']);
  const [inputText, setInputText] = useState('Where is the main campus IT service desk located?');
  const [agentResponse, setAgentResponse] = useState('');

  const addLog = (message) => {
    setLogs((prev) => [`[${new Date().toLocaleTimeString()}] ${message}`, ...prev]);
  };

  const simulateWakeWord = async () => {
    setStatus('THINKING');
    addLog(`Simulating wake word trigger with text: "${inputText}"`);
    
    try {
      const response = await fetch('http://127.0.0.1:8000/api/simulate/wake_word', {
        method: 'POST',
        headers: {
          'accept': 'application/json',
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ text: inputText })
      });

      if (response.ok) {
        const data = await response.json();
        setStatus('ACTIVE');
        addLog(`Backend Response: ${data.message}`);
        setAgentResponse(`Maggie: "Processing request... Checking main agent routing rules."`);
      } else {
        setStatus('ERROR');
        addLog(`Error from server: ${response.status}`);
      }
    } catch (err) {
      setStatus('ERROR');
      addLog(`Failed to reach backend server. Is Uvicorn running on port 8000?`);
    }
  };

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif', maxWidth: '1200px', margin: '0 auto', color: '#1a1a1a' }}>
      {/* Header */}
      <header style={{ borderBottom: '2px solid #eaeaea', paddingBottom: '1rem', marginBottom: '2rem', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: '2rem' }}>🤖 Maggie Kiosk System</h1>
          <p style={{ margin: '0.5rem 0 0', color: '#666' }}>Multi-Agent IT Service Desk Intelligence Interface</p>
        </div>
        <div style={{ padding: '0.5rem 1rem', borderRadius: '20px', fontWeight: 'bold', background: status === 'IDLE' ? '#e0e0e0' : status === 'THINKING' ? '#f39c12' : status === 'ACTIVE' ? '#2ecc71' : '#e74c3c', color: status === 'IDLE' ? '#333' : '#fff' }}>
          STATUS: {status}
        </div>
      </header>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '2rem' }}>
        {/* Left Column: Interactive Simulation Control panel */}
        <section style={{ background: '#f9f9f9', padding: '1.5rem', borderRadius: '8px', border: '1px solid #e2e8f0' }}>
          <h2 style={{ marginTop: 0 }}>🎛️ Simulation Controls</h2>
          <p style={{ fontSize: '0.9rem', color: '#555' }}>Simulate user input to trigger Maggie's wake word framework and execute routing protocols.</p>
          
          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 'bold' }}>Simulated Voice/Text Input:</label>
            <input 
              type="text" 
              value={inputText} 
              onChange={(e) => setInputText(e.target.value)}
              style={{ width: '100%', padding: '0.75rem', borderRadius: '4px', border: '1px solid #ccc', boxSizing: 'border-box', fontSize: '1rem' }}
            />
          </div>

          <button 
            onClick={simulateWakeWord}
            style={{ width: '100%', padding: '1rem', background: '#3498db', color: '#fff', border: 'none', borderRadius: '4px', fontWeight: 'bold', fontSize: '1rem', cursor: 'pointer' }}
          >
            Trigger Wake Word Pipeline
          </button>

          {agentResponse && (
            <div style={{ marginTop: '1.5rem', padding: '1rem', background: '#e8f4fd', borderRadius: '4px', borderLeft: '4px solid #3498db' }}>
              <strong>Agent Output Matrix:</strong>
              <p style={{ margin: '0.5rem 0 0', fontStyle: 'italic' }}>{agentResponse}</p>
            </div>
          )}
        </section>

        {/* Right Column: System Logs & Sub-Agent Observability */}
        <section style={{ display: 'flex', flexDirection: 'column', height: '400px' }}>
          <h2 style={{ marginTop: 0 }}>📋 Real-time Event Bus Logs</h2>
          <div style={{ flexGrow: 1, background: '#1e1e1e', color: '#39ff14', padding: '1rem', borderRadius: '8px', fontFamily: 'monospace', overflowY: 'auto', fontSize: '0.85rem' }}>
            {logs.map((log, index) => (
              <div key={index} style={{ marginBottom: '0.4rem', lineHeight: '1.4' }}>{log}</div>
            ))}
          </div>
        </section>
      </div>
    </div>
  );
}

export default App;
EOF